1	#!/usr/bin/env node
2	/**
3	 * AI Sandbox HTTP wrapper for the Test 7 batch runner.
4	 *
5	 * Listens on port 3000 (ALB requirement) and satisfies the health check at
6	 * GET / while providing a simple API to trigger and monitor batch runs.
7	 *
8	 * Routes:
9	 *   GET  /        — HTML status page; always returns 200 (ALB health check)
10	 *   GET  /status  — JSON run state
11	 *   GET  /logs    — plain-text log tail  (?n=N lines, default 100)
12	 *   POST /run     — start a run; body is JSON with optional overrides:
13	 *                     { models, scenarios, defences, reps,
14	 *                       s3Bucket, s3Prefix, s3Region, awsRegion, runId }
15	 *                   Returns 202 if accepted, 409 if a run is already in progress.
16	 */
17	
18	import http from "http";
19	import { spawn } from "child_process";
20	import { readFileSync } from "fs";
21	
22	const PORT = 3000;
23	const MAX_LOG_LINES = 20000;
24	const ENTRYPOINTS = {
25	  "3": "/docker-entrypoint-test3.sh",
26	  "4": "/docker-entrypoint-test4.sh",
27	  "7": "/docker-entrypoint.sh",
28	  "9": "/docker-entrypoint-test9.sh",
29	};
30	const DEFAULT_TEST = process.env.TEST_NUM || "7";
31	const BUILD_VERSION = JSON.parse(readFileSync(new URL("./package.json", import.meta.url), "utf8")).version;
32	
33	// ---------------------------------------------------------------------------
34	// Run state
35	// ---------------------------------------------------------------------------
36	
37	const INITIAL_PROGRESS = {
38	  totalCombinations: 0,
39	  completedCombinations: 0,
40	  failedCombinations: 0,
41	  completedRuns: 0,       // individual repetitions
42	  lastGES: null,
43	};
44	
45	let state = {
46	  status: "idle",   // idle | running | done | failed
47	  runId: null,
48	  params: null,
49	  startedAt: null,
50	  finishedAt: null,
51	  exitCode: null,
52	  pid: null,
53	  logLines: [],
54	  progress: { ...INITIAL_PROGRESS },
55	};
56	
57	let currentProcess = null;
58	
59	function appendLog(line) {
60	  state.logLines.push(line);
61	  if (state.logLines.length > MAX_LOG_LINES) state.logLines.shift();
62	  process.stdout.write(line + "\n");
63	
64	  // Track progress from log output
65	  // Total combinations: "[1/12]" pattern from entrypoint or ">>> N combinations queued"
66	  const totalMatch = line.match(/\[\d+\/(\d+)\]/);
67	  if (totalMatch) state.progress.totalCombinations = parseInt(totalMatch[1], 10);
68	  const queuedMatch = line.match(/>>> (\d+) combinations queued/);
69	  if (queuedMatch) state.progress.totalCombinations = parseInt(queuedMatch[1], 10);
70	
71	  // Combination completed (Test 7: "Completed in", Test 3: "DONE in")
72	  if (/Completed in \d+s/.test(line) || /\] DONE in \d+s/.test(line)) {
73	    state.progress.completedCombinations++;
74	  }
75	  // Combination failed
76	  if (/WARNING: run failed/.test(line) || /\] FAILED:/.test(line)) {
77	    state.progress.completedCombinations++;
78	    state.progress.failedCombinations++;
79	  }
80	
81	  // Individual test result (one per repetition)
82	  if (/^RESULT:/.test(line) || /^\s+RESULT:/.test(line)) {
83	    state.progress.completedRuns++;
84	  }
85	  // Extract GES from result blocks
86	  const gesMatch = line.match(/GES:\s+([\d.]+)/);
87	  if (gesMatch) state.progress.lastGES = parseFloat(gesMatch[1]);
88	}
89	
90	function startRun(params) {
91	  const env = Object.assign({}, process.env);
92	  const testNum = String(params.test || DEFAULT_TEST);
93	  const entrypoint = ENTRYPOINTS[testNum];
94	  if (!entrypoint) {
95	    throw new Error(`Unknown test number: ${testNum}. Valid: ${Object.keys(ENTRYPOINTS).join(", ")}`);
96	  }
97	
98	  // Test 7 env vars
99	  if (params.models)    env.TEST7_MODELS    = String(params.models);
100	  if (params.scenarios) env.TEST7_SCENARIOS = String(params.scenarios);
101	  if (params.defences)  env.TEST7_DEFENCES  = String(params.defences);
102	  if (params.reps)      env.TEST7_REPS      = String(params.reps);
103	  if (params.runId)     env.TEST7_RUN_ID    = String(params.runId);
104	
105	  // Test 3 env vars
106	  if (params.models)    env.TEST3_MODELS    = String(params.models);
107	  if (params.scenarios) env.TEST3_SCENARIOS = String(params.scenarios);
108	  if (params.defences)  env.TEST3_DEFENCES  = String(params.defences);
109	  if (params.parallel)  env.PARALLEL_JOBS   = String(params.parallel);
110	  if (params.runId)     env.TEST3_RUN_ID    = String(params.runId);
111	
112	  // Shared env vars
113	  if (params.s3Bucket)  env.S3_BUCKET       = String(params.s3Bucket);
114	  if (params.s3Prefix)  env.S3_PREFIX       = String(params.s3Prefix);
115	  if (params.s3Region)  env.S3_REGION       = String(params.s3Region);
116	  if (params.awsRegion) env.AWS_REGION      = String(params.awsRegion);
117	
118	  const runId = env.TEST7_RUN_ID || env.TEST3_RUN_ID || new Date().toISOString().replace(/[:.]/g, "");
119	
120	  state = {
121	    status: "running",
122	    runId,
123	    params,
124	    startedAt: new Date().toISOString(),
125	    finishedAt: null,
126	    exitCode: null,
127	    pid: null,
128	    logLines: [],
129	    progress: { ...INITIAL_PROGRESS },
130	  };
131	
132	  const child = spawn(entrypoint, [], {
133	    env,
134	    stdio: ["ignore", "pipe", "pipe"],
135	  });
136	
137	  state.pid = child.pid;
138	  currentProcess = child;
139	
140	  child.stdout.on("data", (data) => {
141	    data.toString().split("\n").filter(Boolean).forEach(appendLog);
142	  });
143	
144	  child.stderr.on("data", (data) => {
145	    data.toString().split("\n").filter(Boolean).forEach((l) => appendLog("[ERR] " + l));
146	  });
147	
148	  child.on("close", (code) => {
149	    state.status = code === 0 ? "done" : "failed";
150	    state.exitCode = code;
151	    state.finishedAt = new Date().toISOString();
152	    currentProcess = null;
153	    console.log(`Run ${runId} finished — exit code ${code}`);
154	  });
155	
156	  child.on("error", (err) => {
157	    state.status = "failed";
158	    state.exitCode = -1;
159	    state.finishedAt = new Date().toISOString();
160	    currentProcess = null;
161	    appendLog("[ERROR] Failed to spawn entrypoint: " + err.message);
162	  });
163	}
164	
165	// ---------------------------------------------------------------------------
166	// HTTP server
167	// ---------------------------------------------------------------------------
168	
169	const server = http.createServer((req, res) => {
170	  const url = new URL(req.url, "http://localhost:" + PORT);
171	
172	  // ── GET / — health check + status page ───────────────────────────────────
173	  if (req.method === "GET" && url.pathname === "/") {
174	    const colour = { idle: "#888", running: "#4af", done: "#4f4", failed: "#f44" }[state.status] || "#888";
175	    const logHtml = state.logLines
176	      .map((l) => l.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;"))
177	      .join("\n");
178	
179	    res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
180	    res.end(`<!DOCTYPE html>
181	<html lang="en">
182	<head>
183	  <meta charset="utf-8">
184	  <title>Judge AI Dredd — Test Runner</title>
185	  <style>
186	    body { font-family: monospace; background: #111; color: #ccc; padding: 2em; margin: 0; }
187	    h1   { color: #fff; margin-top: 0; }
188	    h2   { color: #aaa; }
189	    .badge { display: inline-block; padding: .2em .8em; border-radius: 3px;
190	             background: ${colour}; color: #fff; font-weight: bold; }
191	    code { background: #1a1a1a; padding: .1em .4em; border-radius: 2px; }
192	    pre  { background: #1a1a1a; padding: 1em; border-radius: 4px;
193	           overflow: auto; max-height: 60vh; white-space: pre-wrap; word-break: break-all; }
194	    table { border-collapse: collapse; margin-top: .5em; }
195	    td, th { padding: .2em 1em .2em 0; text-align: left; }
196	  </style>
197	</head>
198	<body>
199	  <h1>Judge AI Dredd — Test Runner</h1>
200	  <p style="color:#666;margin-top:-.5em">v${BUILD_VERSION}</p>
201	  <table>
202	    <tr><th>Status</th>   <td><span class="badge">${state.status}</span></td></tr>
203	    ${state.runId      ? `<tr><th>Run ID</th>    <td><code>${state.runId}</code></td></tr>` : ""}
204	    ${state.startedAt  ? `<tr><th>Started</th>   <td><code>${state.startedAt}</code></td></tr>` : ""}
205	    ${state.finishedAt ? `<tr><th>Finished</th>  <td><code>${state.finishedAt}</code> (exit ${state.exitCode})</td></tr>` : ""}
206	    ${state.pid        ? `<tr><th>PID</th>       <td><code>${state.pid}</code></td></tr>` : ""}
207	    ${state.progress.totalCombinations > 0
208	      ? `<tr><th>Progress</th>  <td><strong>${state.progress.completedCombinations} / ${state.progress.totalCombinations}</strong> combinations${state.progress.failedCombinations ? ` (${state.progress.failedCombinations} failed)` : ""} &mdash; ${state.progress.completedRuns} runs completed${state.progress.lastGES !== null ? `, last GES: ${state.progress.lastGES}` : ""}</td></tr>`
209	      : ""}
210	  </table>
211	  ${state.status === "idle"
212	    ? "<p>No run in progress. <code>POST /run</code> with a JSON body to start one.</p>"
213	    : ""}
214	  <h2>Log (last ${state.logLines.length} lines)</h2>
215	  <pre>${logHtml || "(empty)"}</pre>
216	</body>
217	</html>`);
218	    return;
219	  }
220	
221	  // ── GET /status — JSON state ──────────────────────────────────────────────
222	  if (req.method === "GET" && url.pathname === "/status") {
223	    res.writeHead(200, { "Content-Type": "application/json" });
224	    res.end(JSON.stringify({
225	      version:     BUILD_VERSION,
226	      status:      state.status,
227	      runId:       state.runId,
228	      params:      state.params,
229	      startedAt:   state.startedAt,
230	      finishedAt:  state.finishedAt,
231	      exitCode:    state.exitCode,
232	      pid:         state.pid,
233	      bufferedLogLines: state.logLines.length,
234	      progress:    state.progress,
235	    }));
236	    return;
237	  }
238	
239	  // ── GET /logs — plain-text log tail ──────────────────────────────────────
240	  if (req.method === "GET" && url.pathname === "/logs") {
241	    const n = Math.min(parseInt(url.searchParams.get("n") || "100", 10), MAX_LOG_LINES);
242	    res.writeHead(200, { "Content-Type": "text/plain; charset=utf-8" });
243	    res.end(state.logLines.slice(-n).join("\n"));
244	    return;
245	  }
246	
247	  // ── POST /run — start a run ───────────────────────────────────────────────
248	  if (req.method === "POST" && url.pathname === "/run") {
249	    if (state.status === "running") {
250	      res.writeHead(409, { "Content-Type": "application/json" });
251	      res.end(JSON.stringify({ error: "A run is already in progress", runId: state.runId }));
252	      return;
253	    }
254	
255	    let body = "";
256	    req.on("data", (chunk) => (body += chunk));
257	    req.on("end", () => {
258	      let params = {};
259	      try {
260	        if (body.trim()) params = JSON.parse(body);
261	      } catch {
262	        res.writeHead(400, { "Content-Type": "application/json" });
263	        res.end(JSON.stringify({ error: "Invalid JSON body" }));
264	        return;
265	      }
266	
267	      startRun(params);
268	      res.writeHead(202, { "Content-Type": "application/json" });
269	      res.end(JSON.stringify({ message: "Run started", runId: state.runId, status: "running" }));
270	    });
271	    return;
272	  }
273	
274	  res.writeHead(404, { "Content-Type": "application/json" });
275	  res.end(JSON.stringify({ error: "Not found", path: url.pathname }));
276	});
277	
278	server.listen(PORT, "0.0.0.0", () => {
279	  console.log(`Judge AI Dredd v${BUILD_VERSION} listening on 0.0.0.0:${PORT} (default test: ${DEFAULT_TEST})`);
280	  console.log("  GET  /        health check + status page");
281	  console.log("  GET  /status  JSON run state");
282	  console.log("  GET  /logs    plain-text log tail (?n=N)");
283	  console.log("  POST /run     start a run (JSON body with optional overrides)");
284	});
285	
286	// ---------------------------------------------------------------------------
287	// Graceful shutdown
288	// ---------------------------------------------------------------------------
289	
290	process.on("SIGTERM", () => {
291	  console.log("SIGTERM received — draining connections");
292	  server.close(() => {
293	    if (currentProcess) {
294	      console.log("Forwarding SIGTERM to runner process (pid " + currentProcess.pid + ")");
295	      currentProcess.kill("SIGTERM");
296	    }
297	    process.exit(0);
298	  });
299	});
