1	/**
2	 * Judge Dredd HTTP Server
3	 *
4	 * Exposes the intent tracking and tool evaluation pipeline as HTTP
5	 * endpoints. Drop a one-liner hook into any Claude Code CLI or SDK
6	 * app and all evaluation logic stays here.
7	 *
8	 * Endpoints:
9	 *   POST /intent    — UserPromptSubmit: register intent, track drift
10	 *   POST /evaluate  — PreToolUse: three-stage tool evaluation
11	 *   POST /track     — PostToolUse: record file/env state
12	 *   POST /end       — Stop: write session log, cleanup
13	 *   GET  /health    — health check
14	 *   GET  /session/:id — get session state (debug)
15	 *
16	 * Usage:
17	 *   npx tsx src/server.ts
18	 *   npx tsx src/server.ts --port 3001
19	 *   npx tsx src/server.ts --judge-model nemotron-3-super --backend ollama
20	 *   npx tsx src/server.ts --backend bedrock
21	 */
22	
23	import { createServer, type IncomingMessage, type ServerResponse } from "node:http";
24	import { parseArgs } from "node:util";
25	import { writeFileSync, appendFileSync, mkdirSync, readFileSync, readdirSync, existsSync } from "node:fs";
26	import { join } from "node:path";
27	import { inspect } from "node:util";
28	import { SessionTracker } from "./session-tracker.js";
29	import { PreToolInterceptor } from "./pretool-interceptor.js";
30	import { exportPolicies } from "./tool-policy.js";
31	import { checkOllama } from "./ollama-client.js";
32	
33	const { values } = parseArgs({
34	  options: {
35	    port: { type: "string", default: "3001" },
36	    mode: { type: "string", default: "autonomous" },
37	    "judge-model": { type: "string", default: "nemotron-3-super" },
38	    backend: { type: "string", default: "ollama" },
39	    "embedding-model": { type: "string", default: "eu.cohere.embed-v4:0" },
40	    "review-threshold": { type: "string", default: "0.6" },
41	    "deny-threshold": { type: "string", default: "0.15" },
42	    "log-dir": { type: "string", default: "./results" },
43	  },
44	});
45	
46	// File logger — mirrors all console output to logs/dredd-YYYY-MM-DD.log
47	const LOG_DIR = "./logs";
48	try { mkdirSync(LOG_DIR, { recursive: true }); } catch {}
49	
50	function getLogFilePath(): string {
51	  const date = new Date().toISOString().slice(0, 10); // YYYY-MM-DD
52	  return join(LOG_DIR, `dredd-${date}.log`);
53	}
54	
55	function appendToLogFile(line: string): void {
56	  try {
57	    appendFileSync(getLogFilePath(), line + "\n");
58	  } catch {}
59	}
60	
61	// Prepend ISO timestamp to every console line so server logs are grep/sortable,
62	// and also write to the daily log file.
63	for (const level of ["log", "info", "warn", "error"] as const) {
64	  const original = console[level].bind(console);
65	  console[level] = (...args: unknown[]) => {
66	    const timestamp = `[${new Date().toISOString()}]`;
67	    original(timestamp, ...args);
68	    const parts = args.map(a => typeof a === "string" ? a : inspect(a, { depth: 4, breakLength: Infinity }));
69	    appendToLogFile(`${timestamp} ${parts.join(" ")}`);
70	  };
71	}
72	
73	const PORT = parseInt(values.port!, 10);
74	type TrustMode = "interactive" | "autonomous" | "learn";
75	
76	const CONFIG = {
77	  /** interactive = vibe coding (trust user prompts, update intent)
78	   *  autonomous  = SDK/pipeline (validate all prompts against original intent) */
79	  mode: (values.mode as TrustMode) ?? "autonomous",
80	  judgeModel: values["judge-model"]!,
81	  judgeBackend: (values.backend as "ollama" | "bedrock")!,
82	  embeddingModel: values["embedding-model"]!,
83	  reviewThreshold: parseFloat(values["review-threshold"]!),
84	  denyThreshold: parseFloat(values["deny-threshold"]!),
85	  logDir: values["log-dir"]!,
86	};
87	
88	// Shared state
89	const feed: { timestamp: string; type: string; tool?: string; stage?: string; allowed?: boolean; reason?: string; prompt?: string; sessionId?: string }[] = [];
90	const MAX_FEED = 200;
91	
92	function addFeed(entry: typeof feed[0]) {
93	  feed.push({ ...entry, timestamp: entry.timestamp ?? new Date().toISOString() });
94	  if (feed.length > MAX_FEED) feed.splice(0, feed.length - MAX_FEED);
95	}
96	
97	const tracker = new SessionTracker(CONFIG.embeddingModel);
98	const interceptor = new PreToolInterceptor({
99	  judgeModel: CONFIG.judgeModel,
100	  judgeBackend: CONFIG.judgeBackend,
101	  embeddingModel: CONFIG.embeddingModel,
102	  reviewThreshold: CONFIG.reviewThreshold,
103	  denyThreshold: CONFIG.denyThreshold,
104	});
105	
106	// Track which sessions have had their goal registered with the interceptor
107	const registeredSessions = new Set<string>();
108	
109	async function readBody(req: IncomingMessage): Promise<string> {
110	  const chunks: Buffer[] = [];
111	  for await (const chunk of req) {
112	    chunks.push(chunk as Buffer);
113	  }
114	  return Buffer.concat(chunks).toString("utf8");
115	}
116	
117	function json(res: ServerResponse, status: number, data: unknown): void {
118	  res.writeHead(status, { "Content-Type": "application/json" });
119	  res.end(JSON.stringify(data));
120	}
121	
122	// =========================================================================
123	// Transcript Backfill
124	// =========================================================================
125	
126	/**
127	 * When Dredd starts mid-session (or restarts), reconstruct state from
128	 * the Claude transcript file. Extracts the original task, tool history,
129	 * and file operations so the session tracker has full context.
130	 */
131	/**
132	 * Walk a Claude JSONL transcript and pull out the most recent user prompt
133	 * together with the assistant text that immediately preceded it. Used to
134	 * build the "intent" handed to the judge in interactive mode — a short user
135	 * reply only makes sense in the context of what the agent just said.
136	 */
137	/**
138	 * Short user replies like "yes", "ok", "do it", "option B" are confirmations
139	 * of the previous assistant turn — they are not standalone goals. Backfill
140	 * must walk past them to find the last substantive user prompt, otherwise
141	 * the judge ends up evaluating tool calls against "yes, option B".
142	 */
143	function isConfirmationPrompt(text: string): boolean {
144	  return (
145	    /^\s*(yes|yeah|yep|ok|okay|sure|do it|go ahead|go|proceed|continue|y|k|confirm|approved?|lgtm|ship it|sounds good|that's right|correct|exactly|please|thanks|thank you|option\s+\w+|👍)\b/i.test(text)
146	    && text.trim().length < 80
147	  );
148	}
149	
150	function extractLastUserAndPriorAssistant(
151	  transcriptPath: string
152	): { lastUser: string | null; priorAssistant: string | null } {
153	  if (!transcriptPath || !existsSync(transcriptPath)) {
154	    return { lastUser: null, priorAssistant: null };
155	  }
156	  try {
157	    const lines = readFileSync(transcriptPath, "utf8").trim().split("\n").filter(Boolean);
158	    // Collect all user prompts with the assistant turn that immediately
159	    // preceded each one, then pick the last *substantive* (non-confirmation)
160	    // entry. Falls back to the very last user prompt if everything is a
161	    // confirmation.
162	    const userTurns: { user: string; prior: string | null }[] = [];
163	    let pendingAssistant: string | null = null;
164	
165	    for (const line of lines) {
166	      try {
167	        const msg = JSON.parse(line);
168	        if (msg.type === "assistant") {
169	          const text = (msg.message?.content ?? [])
170	            .filter((b: any) => b.type === "text")
171	            .map((b: any) => b.text)
172	            .join("\n")
173	            .trim();
174	          if (text) pendingAssistant = text;
175	        } else if (msg.type === "user") {
176	          const text = (msg.message?.content ?? [])
177	            .filter((b: any) => b.type === "text")
178	            .map((b: any) => b.text)
179	            .join("\n")
180	            .trim();
181	          if (text) {
182	            userTurns.push({ user: text, prior: pendingAssistant });
183	          }
184	        }
185	      } catch {}
186	    }
187	
188	    if (userTurns.length === 0) return { lastUser: null, priorAssistant: null };
189	
190	    // Walk backwards for the last substantive prompt.
191	    for (let i = userTurns.length - 1; i >= 0; i--) {
192	      if (!isConfirmationPrompt(userTurns[i].user)) {
193	        return { lastUser: userTurns[i].user, priorAssistant: userTurns[i].prior };
194	      }
195	    }
196	    // All confirmations — fall back to the most recent.
197	    const last = userTurns[userTurns.length - 1];
198	    return { lastUser: last.user, priorAssistant: last.prior };
199	  } catch {
200	    return { lastUser: null, priorAssistant: null };
201	  }
202	}
