204	/**
205	 * Combine a user prompt with the previous assistant response into a single
206	 * "intent" string. Short user replies ("yes", "do that one", "the second
207	 * option") are meaningless without the agent's preceding turn.
208	 */
209	function buildContextualIntent(
210	  userPrompt: string,
211	  priorAssistant: string | null
212	): string {
213	  if (!priorAssistant) return userPrompt;
214	  // Cap the assistant context so the embedding/judge prompt stays bounded.
215	  const trimmed = priorAssistant.length > 2000
216	    ? priorAssistant.substring(priorAssistant.length - 2000)
217	    : priorAssistant;
218	  return `PREVIOUS ASSISTANT RESPONSE:\n${trimmed}\n\nUSER PROMPT:\n${userPrompt}`;
219	}
220	
221	async function backfillFromTranscript(
222	  sessionId: string,
223	  transcriptPath: string
224	): Promise<void> {
225	  if (!transcriptPath || !existsSync(transcriptPath)) return;
226	
227	  try {
228	    const content = readFileSync(transcriptPath, "utf8");
229	    const lines = content.trim().split("\n").filter(Boolean);
230	
231	    let firstUserPrompt: string | null = null;
232	    let turnCount = 0;
233	    const toolCalls: { tool: string; input: Record<string, unknown> }[] = [];
234	    const filesRead: string[] = [];
235	    const filesWritten: { path: string; content: string; isEdit: boolean }[] = [];
236	
237	    for (const line of lines) {
238	      try {
239	        const msg = JSON.parse(line);
240	
241	        // Extract first user message as original intent
242	        if (msg.type === "user" && !firstUserPrompt) {
243	          const textBlocks = (msg.message?.content ?? [])
244	            .filter((b: any) => b.type === "text")
245	            .map((b: any) => b.text);
246	          if (textBlocks.length > 0) {
247	            firstUserPrompt = textBlocks.join("\n");
248	          }
249	        }
250	
251	        // Count user messages as turns
252	        if (msg.type === "user" && msg.message?.content?.some((b: any) => b.type === "text")) {
253	          turnCount++;
254	        }
255	
256	        // Extract tool calls from assistant messages
257	        if (msg.type === "assistant") {
258	          const blocks = msg.message?.content ?? [];
259	          for (const block of blocks) {
260	            if (block.type === "tool_use") {
261	              const tool = block.name;
262	              const input = block.input ?? {};
263	              toolCalls.push({ tool, input });
264	
265	              // Track file operations
266	              if (tool === "Read") {
267	                filesRead.push(String(input.file_path ?? ""));
268	              }
269	              if (tool === "Write") {
270	                filesWritten.push({
271	                  path: String(input.file_path ?? ""),
272	                  content: String(input.content ?? ""),
273	                  isEdit: false,
274	                });
275	              }
276	              if (tool === "Edit") {
277	                filesWritten.push({
278	                  path: String(input.file_path ?? ""),
279	                  content: String(input.new_string ?? ""),
280	                  isEdit: true,
281	                });
282	              }
283	            }
284	          }
285	        }
286	      } catch {
287	        // Skip malformed lines
288	      }
289	    }
290	
291	    // Prefer the *last* user prompt (combined with the prior assistant turn)
292	    // as the goal — backfill is only used when Dredd starts mid-session, and
293	    // the most recent exchange is what the agent is currently acting on.
294	    const { lastUser, priorAssistant } = extractLastUserAndPriorAssistant(transcriptPath);
295	    const goalPrompt = lastUser ?? firstUserPrompt;
296	    if (!goalPrompt) return;
297	    const contextualGoal = buildContextualIntent(goalPrompt, priorAssistant);
298	
299	    console.log(
300	      `  [BACKFILL] Session ${sessionId.substring(0, 8)}: ` +
301	      `${turnCount} turns, ${toolCalls.length} tools, ` +
302	      `${filesRead.length} reads, ${filesWritten.length} writes ` +
303	      `from transcript`
304	    );
305	
306	    // Register the most-recent intent (with prior assistant context)
307	    await tracker.registerIntent(sessionId, goalPrompt);
308	    await interceptor.registerGoal(contextualGoal);
309	    registeredSessions.add(sessionId);
310	
311	    // Replay file operations into the tracker
312	    for (const path of filesRead) {
313	      tracker.recordFileRead(sessionId, path, "(backfilled)");
314	    }
315	    for (const file of filesWritten) {
316	      tracker.recordFileWrite(sessionId, file.path, file.content, file.isEdit);
317	    }
318	
319	    // Record tool calls
320	    for (const tc of toolCalls) {
321	      tracker.recordToolCall(sessionId, tc.tool, tc.input, "allow", null);
322	    }
323	
324	    console.log(
325	      `  [BACKFILL] Latest intent: "${goalPrompt.substring(0, 60)}..." ` +
326	      `(prior assistant context: ${priorAssistant ? "yes" : "no"})`
327	    );
328	  } catch (err) {
329	    console.error(
330	      `  [BACKFILL] Failed for session ${sessionId.substring(0, 8)}: ${err instanceof Error ? err.message : String(err)}`
331	    );
332	  }
333	}
